using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    [DataRow("Doe", "John", "Doe, John", DisplayName = "Standard names")]
    [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Different names")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    public void FullName_WithLastAndFirst_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
    {
        // Arrange — use Student as a concrete implementation of abstract Person
        var person = new Student { LastName = lastName, FirstMidName = firstName };

        // Act
        var result = person.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSetAndRetrieved()
    {
        // Arrange
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        // Assert
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Instructor_HireDate_CanBeSetAndRetrieved()
    {
        // Arrange
        var date = new DateTime(2000, 3, 15);
        var instructor = new Instructor { HireDate = date };

        // Assert
        Assert.AreEqual(date, instructor.HireDate);
    }

    [TestMethod]
    public void Student_Enrollments_InitiallyNull()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Instructor_CourseAssignments_InitiallyNull()
    {
        // Arrange & Act
        var instructor = new Instructor();

        // Assert
        Assert.IsNull(instructor.CourseAssignments);
    }

    [TestMethod]
    public void Course_CourseID_IsNotAutoGenerated()
    {
        // Arrange & Act
        var course = new Course { CourseID = 1050 };

        // Assert — CourseID has [DatabaseGenerated(None)] so it must be set manually
        Assert.AreEqual(1050, course.CourseID);
    }

    [TestMethod]
    public void Department_RowVersion_CanBeSetAndRetrieved()
    {
        // Arrange
        var rowVersion = new byte[] { 1, 2, 3, 4, 5, 6, 7, 8 };
        var department = new Department { RowVersion = rowVersion };

        // Assert
        CollectionAssert.AreEqual(rowVersion, department.RowVersion);
    }

    [TestMethod]
    public void Department_InstructorID_IsNullable()
    {
        // Arrange & Act
        var department = new Department { InstructorID = null };

        // Assert
        Assert.IsNull(department.InstructorID);
    }

    [TestMethod]
    public void Enrollment_Grade_IsNullable()
    {
        // Arrange & Act
        var enrollment = new Enrollment();

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
    public void Enrollment_Grade_CanBeSetToAllValues(Grade grade)
    {
        // Arrange & Act
        var enrollment = new Enrollment { Grade = grade };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    [TestMethod]
    public void Notification_Properties_CanBeSetAndRetrieved()
    {
        // Arrange
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = now,
            CreatedBy = "admin",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Test message", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void Notification_IsRead_CanBeSetToTrue()
    {
        // Arrange & Act
