using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _service = new NotificationService();
        // Drain the static queue to isolate tests
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service.Dispose();
    }

    [TestMethod]
    public void SendNotification_ValidInput_CanBeReceived()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Student", result.EntityType);
        Assert.AreEqual("1", result.EntityId);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student 'John Doe' has been created", result!.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Course 'Chemistry' has been updated", result!.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Department 'Engineering' has been deleted", result!.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student (ID: 42) has been created", result!.Message);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin@test.com");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("admin@test.com", result!.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_SetsSystemAsCreatedBy()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("System", result!.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsFalse(result!.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsOperationAsString()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.UPDATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("UPDATE", result!.Operation);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToApproximatelyNow()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsTrue(result!.CreatedAt >= before && result.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_SetsEntityType()
    {
        // Act
        _service.SendNotification("Course", "101", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Course", result!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_FIFO_ReturnsInOrder()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Student", "2", EntityOperation.UPDATE);
        _service.SendNotification("Student", "3", EntityOperation.DELETE);

        // Act & Assert
        Assert.AreEqual("1", _service.ReceiveNotification()!.EntityId);
        Assert.AreEqual("2", _service.ReceiveNotification()!.EntityId);
        Assert.AreEqual("3", _service.ReceiveNotification()!.EntityId);
        Assert.IsNull(_service.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert — MarkAsRead is a no-op for in-memory implementation
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert — should not throw
        service.Dispose();
    }

    [TestMethod]
    public void SendNotification_MultipleNotifications_AllCanBeReceived()
    {
        // Act
        for (int i = 0; i < 5; i++)
        {
            _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Assert
        var received = new List<Notification>();
        Notification? n;
        while ((n = _service.ReceiveNotification()) != null)
        {
            received.Add(n);
        }
        Assert.AreEqual(5, received.Count);
    }

    [TestMethod]
    public void SendNotification_WithDisplayNameOverload_SetsAllProperties()
    {
        // Act
        _service.SendNotification("Instructor", "10", "Dr. Smith", EntityOperation.UPDATE, "admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Instructor", result.EntityType);
        Assert.AreEqual("10", result.EntityId);
        Assert.AreEqual("UPDATE", result.Operation);
        Assert.AreEqual("Instructor 'Dr. Smith' has been updated", result.Message);
        Assert.AreEqual("admin", result.CreatedBy);
        Assert.IsFalse(result.IsRead);
    }
}

