    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds5Instructors()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(5, _context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds4Departments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(4, _context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds7Courses()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(7, _context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds11Enrollments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(11, _context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds3OfficeAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(3, _context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_Seeds8CourseAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_DatabaseWithExistingStudents_DoesNotSeed()
    {
        // Arrange — pre-seed a single student
        _context.Students.Add(new Student
        {
            FirstMidName = "Existing",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();

        // Act
        DbInitializer.Initialize(_context);

        // Assert — should still have only the 1 pre-seeded student
        Assert.AreEqual(1, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SeedsAlexanderStudent_WithCorrectData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var alexander = _context.Students.First(s => s.LastName == "Alexander");
        Assert.AreEqual("Carson", alexander.FirstMidName);
        Assert.AreEqual(DateTime.Parse("2010-09-01"), alexander.EnrollmentDate);
    }

    [TestMethod]
    public void Initialize_SeedsChemistryCourse_WithCorrectData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var chemistry = _context.Courses.First(c => c.Title == "Chemistry");
        Assert.AreEqual(1050, chemistry.CourseID);
        Assert.AreEqual(3, chemistry.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsEngineeringDepartment_WithCorrectBudget()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var engineering = _context.Departments.First(d => d.Name == "Engineering");
        Assert.AreEqual(350000m, engineering.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsAlexanderEnrollments_WithCorrectGrades()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var alexander = _context.Students.First(s => s.LastName == "Alexander");
        var enrollments = _context.Enrollments.Where(e => e.StudentID == alexander.ID).ToList();
        Assert.AreEqual(3, enrollments.Count);
        Assert.IsTrue(enrollments.Any(e => e.Grade == Grade.A));
        Assert.IsTrue(enrollments.Any(e => e.Grade == Grade.B));
        Assert.IsTrue(enrollments.Any(e => e.Grade == Grade.C));
    }

    [TestMethod]
    public void Initialize_SeedsFakhouriOfficeAssignment_WithCorrectLocation()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var fakhouri = _context.Instructors.First(i => i.LastName == "Fakhouri");
        var office = _context.OfficeAssignments.First(o => o.InstructorID == fakhouri.ID);
        Assert.AreEqual("Smith 17", office.Location);
    }

    [TestMethod]
    public void Initialize_CalledTwice_DoesNotDuplicateData()
    {
        // Act
        DbInitializer.Initialize(_context);
        DbInitializer.Initialize(_context);

        // Assert — should not duplicate because second call exits early
        Assert.AreEqual(8, _context.Students.Count());
        Assert.AreEqual(5, _context.Instructors.Count());
    }
}

