using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _controller = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelper.CreateContext();
        // Seed test students with different enrollment dates
        _context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Bob", LastName = "Jones", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Charlie", LastName = "Brown", EnrollmentDate = DateTime.Parse("2021-09-01") }
        );
        _context.SaveChanges();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_ReturnsViewResult()
    {
        // Act
