using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelper.CreateContext();
        SeedStudents();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        var dept = new Department { Name = "Engineering", Budget = 100000, StartDate = DateTime.Parse("2020-01-01") };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);

        var student1 = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") };
        var student2 = new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2019-09-01") };
        var student3 = new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2021-09-01") };
        _context.Students.AddRange(student1, student2, student3);
        _context.SaveChanges();

        // Add an enrollment for Details test
        _context.Enrollments.Add(new Enrollment { StudentID = student1.ID, CourseID = 100, Grade = Grade.A });
        _context.SaveChanges();
    }

    // ==================== Index Tests ====================

    [TestMethod]
    public void Index_DefaultSort_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.AreEqual(3, model!.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.AreEqual("Anand", model![0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert — 2019 < 2020 < 2021
        Assert.AreEqual("Alonso", model![0].LastName);
        Assert.AreEqual("Alexander", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert — 2021 > 2020 > 2019
        Assert.AreEqual("Anand", model![0].LastName);
        Assert.AreEqual("Alexander", model[1].LastName);
        Assert.AreEqual("Alonso", model[2].LastName);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Carson", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.AreEqual(0, model!.Count);
    }

    [TestMethod]
    public void Index_WithSearchString_SetsPageToOne()
    {
        // Act
        var result = _controller.Index(null, null, "A", 5) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert — when searchString is provided, page resets to 1
        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_WithoutSearchString_UsesCurrentFilter()
    {
        // Act
        _controller.Index(null, "Alexander", null, null);

        // Assert
        Assert.AreEqual("Alexander", _controller.ViewBag.CurrentFilter);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Act
        _controller.Index(null, null, null, null);

        // Assert — default sort: NameSortParm="name_desc", DateSortParm="Date"
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_SetsCorrectSortParameters()
    {
        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_SetsCorrectSortParameters()
    {
        // Act
        _controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    // ==================== Details Tests ====================

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var studentId = _context.Students.First(s => s.LastName == "Alexander").ID;

        // Act
        var result = _controller.Details(studentId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
        Assert.AreEqual("Carson", student.FirstMidName);
    }

    [TestMethod]
    public void Details_ValidId_IncludesEnrollments()
    {
        // Arrange
        var studentId = _context.Students.First(s => s.LastName == "Alexander").ID;

        // Act
        var result = _controller.Details(studentId) as ViewResult;
        var student = result!.Model as Student;

        // Assert — Alexander has one enrollment
        Assert.IsNotNull(student!.Enrollments);
        Assert.AreEqual(1, student.Enrollments.Count);
    }

    // ==================== Create GET Tests ====================

    [TestMethod]
    public void CreateGet_ReturnsViewResult()
    {
        // Act
        var result = _controller.Create();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreateGet_ReturnsViewWithStudentModel()
    {
        // Act
        var result = _controller.Create() as ViewResult;
        var model = result!.Model as Student;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // ==================== Create POST Tests ====================

    [TestMethod]
    public void CreatePost_ValidModel_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidModel_AddsStudentToDatabase()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        // Act
        _controller.Create(student);

        // Assert — 3 seeded + 1 new
        Assert.AreEqual(4, _context.Students.Count());
    }

    [TestMethod]
    public void CreatePost_DefaultEnrollmentDate_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = default
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void CreatePost_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreatePost_DateBeforeMinimum_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // ==================== Edit GET Tests ====================

    [TestMethod]
    public void EditGet_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void EditGet_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var studentId = _context.Students.First(s => s.LastName == "Alexander").ID;

        // Act
        var result = _controller.Edit(studentId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.AreEqual("Alexander", student!.LastName);
    }

    [TestMethod]
    public void EditGet_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // ==================== Edit POST Tests ====================

    [TestMethod]
    public void EditPost_ValidModel_RedirectsToIndex()
    {
        // Arrange
        var existingStudent = _context.Students.First(s => s.LastName == "Alexander");
        _context.Entry(existingStudent).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var student = new Student
        {
            ID = existingStudent.ID,
