using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private Mock<IWebHostEnvironment> _mockEnv = null!;
    private Mock<ILogger<CoursesController>> _mockLogger = null!;
    private CoursesController _controller = null!;
    private string _tempDir = null!;
    private Department _department = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelper.CreateContext();
        _tempDir = Path.Combine(Path.GetTempPath(), "contoso-test-" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempDir);

        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _mockLogger = new Mock<ILogger<CoursesController>>();

        SeedData();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    private void SeedData()
    {
        _department = new Department { Name = "Engineering", Budget = 100000, StartDate = DateTime.Parse("2020-01-01") };
        _context.Departments.Add(_department);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = _department.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = _department.DepartmentID }
        );
        _context.SaveChanges();
    }

    // ==================== Index Tests ====================

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_CoursesIncludeDepartment()
    {
        // Act
        var result = _controller.Index() as ViewResult;
        var model = result!.Model as List<Course>;

        // Assert
        Assert.IsTrue(model!.All(c => c.Department != null));
        Assert.AreEqual("Engineering", model[0].Department.Name);
    }

    // ==================== Details Tests ====================

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
    }

    [TestMethod]
    public void Details_ValidId_IncludesDepartment()
    {
        // Act
        var result = _controller.Details(1050) as ViewResult;
        var course = result!.Model as Course;

        // Assert
        Assert.IsNotNull(course!.Department);
        Assert.AreEqual("Engineering", course.Department.Name);
    }

    // ==================== Create GET Tests ====================

