        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void CreatePost_FileTooLarge_AddsModelError()
    {
        // Arrange
        var course = new Course { CourseID = 2000, Title = "New Course", Credits = 3, DepartmentID = _department.DepartmentID };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("image.jpg");
        mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB limit

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void CreatePost_ValidFile_RedirectsToIndex()
    {
        // Arrange
        var course = new Course { CourseID = 2000, Title = "New Course", Credits = 3, DepartmentID = _department.DepartmentID };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("image.jpg");
        mockFile.Setup(f => f.Length).Returns(1024);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidFile_SetsImagePath()
    {
        // Arrange
        var course = new Course { CourseID = 2000, Title = "New Course", Credits = 3, DepartmentID = _department.DepartmentID };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("image.png");
        mockFile.Setup(f => f.Length).Returns(1024);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        _controller.Create(course, mockFile.Object);

        // Assert
        var savedCourse = _context.Courses.First(c => c.CourseID == 2000);
        Assert.IsNotNull(savedCourse.TeachingMaterialImagePath);
        Assert.IsTrue(savedCourse.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        Assert.IsTrue(savedCourse.TeachingMaterialImagePath.EndsWith(".png"));
    }

    [TestMethod]
    [DataRow(".jpg", DisplayName = "JPEG file")]
    [DataRow(".jpeg", DisplayName = "JPEG (long ext)")]
    [DataRow(".png", DisplayName = "PNG file")]
    [DataRow(".gif", DisplayName = "GIF file")]
    [DataRow(".bmp", DisplayName = "BMP file")]
    public void CreatePost_AllowedExtension_AcceptsFile(string extension)
    {
        // Arrange
        var courseId = 2000 + extension.GetHashCode(); // unique ID per extension
        var course = new Course { CourseID = Math.Abs(courseId) % 90000 + 10000, Title = "Course", Credits = 3, DepartmentID = _department.DepartmentID };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"image{extension}");
        mockFile.Setup(f => f.Length).Returns(1024);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
    }

