using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;
    private Instructor _instructor1 = null!;
    private Instructor _instructor2 = null!;
    private Department _department = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelper.CreateContext();
        SeedData();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        _instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        _instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(_instructor1, _instructor2);
        _context.SaveChanges();

        _department = new Department
        {
            Name = "English",
            Budget = 350000m,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = _instructor1.ID
        };
        _context.Departments.Add(_department);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = _department.DepartmentID };
        var course2 = new Course { CourseID = 2042, Title = "Literature", Credits = 4, DepartmentID = _department.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        // Add course assignment
        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 2021, InstructorID = _instructor1.ID });
        _context.SaveChanges();
    }

    // ==================== Index Tests ====================

    [TestMethod]
    public void Index_ReturnsViewWithInstructorIndexData()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Instructors);
    }

    [TestMethod]
    public void Index_ReturnsAllInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;
        var model = result!.Model as InstructorIndexData;

        // Assert
        var instructors = model!.Instructors.ToList();
        Assert.AreEqual(2, instructors.Count);
    }

    [TestMethod]
    public void Index_OrdersInstructorsByLastName()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;
        var model = result!.Model as InstructorIndexData;

        // Assert
        var instructors = model!.Instructors.ToList();
        Assert.AreEqual("Abercrombie", instructors[0].LastName);
        Assert.AreEqual("Fakhouri", instructors[1].LastName);
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsViewBagInstructorID()
    {
        // Act
        _controller.Index(_instructor1.ID, null);

        // Assert
        Assert.AreEqual(_instructor1.ID, _controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Act
        var result = _controller.Index(_instructor1.ID, null) as ViewResult;
        var model = result!.Model as InstructorIndexData;

        // Assert
        Assert.IsNotNull(model!.Courses);
        var courses = model.Courses.ToList();
        Assert.AreEqual(1, courses.Count);
        Assert.AreEqual("Composition", courses[0].Title);
    }

    // ==================== Details Tests ====================

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Details(_instructor1.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
        Assert.AreEqual("Kim", instructor.FirstMidName);
    }

