    public void CreateGet_SetsViewBagCourses()
    {
        // Act
        _controller.Create();

        // Assert
        Assert.IsNotNull(_controller.ViewBag.Courses);
        var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
        Assert.IsNotNull(courses);
        Assert.AreEqual(2, courses.Count);
    }

    // ==================== Create POST Tests ====================

    [TestMethod]
    public void CreatePost_ValidModel_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Roger",
            LastName = "Harui",
            HireDate = DateTime.Parse("1998-07-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidModel_AddsInstructorToDatabase()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Roger",
            LastName = "Harui",
            HireDate = DateTime.Parse("1998-07-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        _controller.Create(instructor, null!);

        // Assert — 2 seeded + 1 new
        Assert.AreEqual(3, _context.Instructors.Count());
    }

    [TestMethod]
    public void CreatePost_WithSelectedCourses_AddsCourseAssignments()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Roger",
            LastName = "Harui",
            HireDate = DateTime.Parse("1998-07-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "2021", "2042" };

        // Act
        _controller.Create(instructor, selectedCourses);

        // Assert
        var savedInstructor = _context.Instructors
            .Include(i => i.CourseAssignments)
            .First(i => i.LastName == "Harui");
        Assert.AreEqual(2, savedInstructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void CreatePost_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = DateTime.Parse("1998-07-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // ==================== Delete GET Tests ====================

    [TestMethod]
    public void DeleteGet_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void DeleteGet_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Delete(_instructor2.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.AreEqual("Fakhouri", instructor!.LastName);
    }

    [TestMethod]
    public void DeleteGet_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // ==================== DeleteConfirmed Tests ====================

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorFromDatabase()
    {
        // Act
        _controller.DeleteConfirmed(_instructor2.ID);

        // Assert
        Assert.AreEqual(1, _context.Instructors.Count());
        Assert.IsFalse(_context.Instructors.Any(i => i.LastName == "Fakhouri"));
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        // Act
        var result = _controller.DeleteConfirmed(_instructor2.ID);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorIsDepartmentAdmin_NullifiesAdminReference()
    {
        // Arrange — _instructor1 is the admin of _department

        // Act
        _controller.DeleteConfirmed(_instructor1.ID);

        // Assert
        var department = _context.Departments.First(d => d.Name == "English");
        Assert.IsNull(department.InstructorID);
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorNotDepartmentAdmin_DoesNotAffectDepartments()
    {
        // Arrange — _instructor2 is NOT an admin of any department

        // Act
        _controller.DeleteConfirmed(_instructor2.ID);

        // Assert — _department still has _instructor1 as admin
        var department = _context.Departments.First(d => d.Name == "English");
        Assert.AreEqual(_instructor1.ID, department.InstructorID);
    }
}

