using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Text.Json;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;
    private NotificationService _notificationService = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelper.CreateContext();
        _controller = new NotificationsController(_context);
        _notificationService = new NotificationService();
        // Drain the static queue to isolate tests
        while (_notificationService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
        _notificationService.Dispose();
    }

    /// <summary>
    /// Helper to extract properties from anonymous type returned by Json().
    /// Anonymous types are internal to the source assembly, so we serialize to JSON and parse.
    /// </summary>
    private static JsonElement GetJsonValue(JsonResult jsonResult)
    {
        var json = JsonSerializer.Serialize(jsonResult.Value);
        return JsonDocument.Parse(json).RootElement;
    }

    // ==================== GetNotifications Tests ====================

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);

        var value = GetJsonValue(jsonResult);
        Assert.IsTrue(value.GetProperty("success").GetBoolean());
        Assert.AreEqual(0, value.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange — add notifications via the shared static queue
        _notificationService.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        _notificationService.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        var value = GetJsonValue(result!);
        Assert.IsTrue(value.GetProperty("success").GetBoolean());
        Assert.AreEqual(2, value.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10Notifications()
    {
        // Arrange — add 15 notifications
        for (int i = 0; i < 15; i++)
        {
            _notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        var value = GetJsonValue(result!);
        Assert.IsTrue(value.GetProperty("success").GetBoolean());
        Assert.AreEqual(10, value.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_ReturnsNotificationData()
    {
        // Arrange
        _notificationService.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        var value = GetJsonValue(result!);
        var notifications = value.GetProperty("notifications");
        Assert.AreEqual(1, notifications.GetArrayLength());
        Assert.AreEqual("Student", notifications[0].GetProperty("EntityType").GetString());
    }

    // ==================== MarkAsRead Tests ====================

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1) as JsonResult;

        // Assert
        var value = GetJsonValue(result!);
        Assert.IsTrue(value.GetProperty("success").GetBoolean());
    }

    // ==================== Index Tests ====================

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }
}

